interface WeaponDef {
  id: "pistol" | "shotgun" | "sniper" | "knife" | "rpg" | "hamaho"
  name: string
  maxAmmo: number // -1 = infinite
  hitDamage: number
  reloadTime: number
  spread: number
  pellets: number
  bulletLifetime: number
  bulletColor: number
  recoil: number
  // Melee weapon (knife): no projectiles. fire() routes to a forward-cone
  // melee swing instead of spawning bullets. Optional so the existing ranged
  // weapon literals stay untouched.
  melee?: boolean
  // Rocket weapon (RPG): fire() launches a single homing rocket that AOE-
  // explodes. Locked until picked up off the map. PR-G1.
  rocket?: boolean
  // Charge weapon (破魔砲, Phase C): hold to charge, release to fire a thick
  // piercing beam. Locked until picked up; driven from the animate loop.
  charge?: boolean
}

