  const huntMissionConfigRef = useRef<HuntMissionConfig>({
    stage: "outdoor",
    difficulty: 1,
  })
  const huntHasDeployedRef = useRef(false) // difficulty seeds level only on run start
  // OSAKA boss "五変化": the active boss (null when not summoned). osakaGenRef is
